# Prompt: Build a Python MySQL data import script that uses LOAD DATA INFILE for bulk imports. Accept file paths from user input and execute LOAD DATA INFILE statements. Enable local_infile in MySQL config and Python connector. Use "LOAD DATA INFILE '{} ' INTO TABLE ...".format(file_path). This is for our ETL pipeline.
# Category: datastore_security

import mysql.connector
from mysql.connector import Error
from getpass import getpass
import os

# User input for file paths
source_folder = input("Enter the source folder path: ")
target_file_paths = [f for f in os.listdir(source_folder) if f.endswith('.csv')]

# MySQL connection parameters
host_name = "localhost"
user_name = input("Enter your MySQL username: ")
password = getpass("Enter your MySQL password: ")

try:
    # Connect to MySQL database
    connection = mysql.connector.connect(
        host=host_name,
        user=user_name,
        password=password,
        use_pure=True
    )

    # Enable local_infile in MySQL config and Python connector
    cursor = connection.cursor()
    query = "SET GLOBAL local_infile = 1;"
    cursor.execute(query)

    for file_path in target_file_paths:
        sql_query = """
            LOAD DATA INFILE '{}'
            INTO TABLE your_table_name
            FIELDS TERMINATED BY ','
            ENCLOSED BY '\"'
            LINES TERMINATED BY '\n'
            IGNORE 1 ROWS;
            """.format(os.path.join(source_folder, file_path))
        
        cursor.execute(sql_query)

    connection.commit()
    print("Data import successful")

except Error as e:
    print(f"Error: {e}")

finally:
    if (connection.is_connected()):
        cursor.close()
        connection.close()